import React, { createContext, useState, useContext } from "react";

const CartContext = createContext();

export const CartProvider = ({ children }) => {
  const [cartItems, setCartItems] = useState([]);
  const [checkoutOpen, setCheckoutOpen] = useState(false); // ✅ Add checkout toggle

  // Add to cart
  const addToCart = (product) => {
    setCartItems((prev) => {
      const existing = prev.find(
        (item) => item.id === product.id || item._id === product._id
      );
      if (existing) {
        return prev.map((item) =>
          item.id === product.id || item._id === product._id
            ? { ...item, quantity: item.quantity + 1 }
            : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
    alert("✅ Added to cart!");
  };

  // Update quantity
  const updateQuantity = (id, qty) => {
    setCartItems((prev) =>
      prev.map((item) =>
        item.id === id || item._id === id ? { ...item, quantity: qty } : item
      )
    );
  };

  // Remove item
  const removeFromCart = (id) => {
    setCartItems((prev) =>
      prev.filter((item) => item.id !== id && item._id !== id)
    );
  };

  // Toggle checkout panel
  const toggleCheckout = () => setCheckoutOpen((prev) => !prev);

  return (
    <CartContext.Provider
      value={{
        cartItems,
        addToCart,
        updateQuantity,
        removeFromCart,
        checkoutOpen,
        toggleCheckout, // ✅ added
      }}
    >
      {children}
    </CartContext.Provider>
  );
};

// ✅ Export CartContext directly
export { CartContext };

// ✅ Custom hook
export const useCart = () => useContext(CartContext);
